	configList[configName]['desc'] = nil;
end

--获取配置表--
function ConfigAll.GetConfig(configName)
	return configList[configName];
end

--获取参数--
function ConfigAll.GetParam(configName)
	local tb = configExpr[configName]
	local ret = {}
	for key, v in pairs(tb) do
		local begin = string.find(v, '>')
		if begin ~= nil then
			local str_param = string.sub(v, begin + 1)
			local begin_str = string.find(str_param,':')
			local ret_type = str_param
			local ret_param = ''
			if begin_str ~= nil then
				ret_type = string.sub(str_param, 1, begin_str - 1)
				ret_param = string.sub(str_param, begin_str + 1)
			end
			ret[key] = {
				ret_type = ret_type,
				param = ret_param,
			}
		end
	end
	return ret;
end

--移除配置表--
function ConfigAll.RemoveConfig(configName)
	configList[configName] = nil;
end

